function c(t,p){const e={};p.map(n=>{e[n]=new Array(t.length).fill(1,0,1).fill(0,1),e[`${n}-index`]=0});for(let n=1;n<t.length;n++)p.map(o=>{const r=e[`${o}-index`];t[n][o]===t[n-1][o]?e[o][r]++:(e[`${o}-index`]=n,e[o][n]=1)});return function({row:n,column:o,rowIndex:r,columnIndex:l}){if(p.includes(o.property)){const s=e[o.property][r];return s>0?{rowspan:s,colspan:1}:{rowspan:0,colspan:0}}return{rowspan:1,colspan:1}}}export{c as g};
